using System;

class Program
{
    static void Main(string[] args)
    {
        // İstifadəçi girişini simulyasiya edirik
        string input = "25"; // Simulyasiya edilmiş giriş
        int age = int.Parse(input);

        Console.WriteLine($"Daxil edilən yaş: {age}");
        if (age >= 18)
        {
            Console.WriteLine("Siz yetkin yaşdasınız.");
        }
        else
        {
            Console.WriteLine("Siz yetkin yaşda deyilsiniz.");
        }
    }
}
// Output:
// Daxil edilən yaş: 25
// Siz yetkin yaşdasınız.

